const config = require('./src/config');
const fetch = require('node-fetch');

const payload = {"content":"<h2>Khái niệm</h2><p><strong>Ansible</strong> là một công cụ mã nguồn mở, được phát triển để tự động hóa các tác vụ trong hệ thống công nghệ thông tin. Được sử dụng phổ biến trong việc quản lý cấu hình, triển khai ứng dụng và tự động hóa các tác vụ hành chính, Ansible cho phép người dùng tự động hóa các công việc phức tạp và giảm thiểu lỗi do thao tác thủ công.</p><p>Điều đặc biệt về Ansible là khả năng <strong>không cần cài đặt agent</strong> trên các máy chủ từ xa, điều này làm cho nó trở thành một công cụ nhẹ nhàng và dễ dàng triển khai. Ansible sử dụng giao thức <strong>SSH</strong> (cho Linux/Unix) hoặc <strong>WinRM</strong> (cho Windows) để kết nối và thực thi các tác vụ trên các hệ thống từ xa.</p><p><strong>Inventory (Danh Sách Máy Chủ)</strong></p><p>Trong Ansible, <strong>Inventory</strong> là danh sách các máy chủ hoặc nút mà bạn muốn quản lý. Inventory có thể được định nghĩa tĩnh (trong một tệp tin cấu hình) hoặc động (sử dụng dịch vụ đám mây như AWS).</p><p><strong>Playbook</strong></p><p>Playbook là một tệp tin <strong>YAML</strong> chứa các bước (plays) mà Ansible sẽ thực hiện. Mỗi play có thể chứa nhiều tác vụ (tasks), mỗi tác vụ sẽ thực hiện một công việc cụ thể trên các máy chủ mục tiêu.</p><p><strong>Roles (Vai Trò)</strong></p><p>Ansible hỗ trợ <strong>Roles</strong>, một cách để tổ chức các tác vụ thành các phần có thể tái sử dụng. Điều này giúp cấu trúc playbook trở nên rõ ràng và dễ bảo trì.</p><p><strong>Mô-đun</strong></p><p>Mỗi tác vụ trong playbook sẽ sử dụng một mô-đun cụ thể của Ansible để thực hiện công việc. Ví dụ, mô-đun yum dùng để cài đặt phần mềm trên hệ thống sử dụng <strong>Red Hat</strong> hoặc <strong>CentOS</strong>, trong khi mô-đun service dùng để quản lý trạng thái của các dịch vụ.</p><p><strong>Idempotent (Không Thay Đổi Nếu Không Cần Thiết)</strong></p><p>Ansible đảm bảo tính <strong>idempotent</strong>, nghĩa là nếu bạn chạy lại một playbook nhiều lần, kết quả cuối cùng sẽ không thay đổi trừ khi có sự thay đổi thực sự trong hệ thống.</p><h2>Các tính năng chính</h2><p>Ansible sở hữu nhiều tính năng nổi bật giúp tự động hóa quản lý hệ thống và các tác vụ hành chính. Dưới đây là một số tính năng chính:</p><ul><li><p><strong>Quản Lý Cấu Hình</strong></p></li></ul><p>Ansible cho phép bạn quản lý cấu hình của nhiều máy chủ đồng thời, giúp đảm bảo rằng tất cả các hệ thống đều có cùng một cấu hình chính xác. Bạn có thể dễ dàng cài đặt phần mềm, cấu hình hệ thống và đảm bảo tính nhất quán trên các máy chủ.</p><ul><li><p><strong>Tự Động Hóa Tác Vụ</strong></p></li></ul><p>Ansible giúp tự động hóa các tác vụ hành chính thường xuyên như cài đặt phần mềm, cập nhật hệ thống, quản lý tường lửa, và thậm chí triển khai các ứng dụng trên nhiều máy chủ chỉ với vài dòng lệnh.</p><ul><li><p><strong>Tích Hợp Dễ Dàng với Hệ Thống CI/CD</strong></p></li></ul><p>Ansible có thể được tích hợp vào các hệ thống <strong>CI/CD</strong> (Continuous Integration/Continuous Deployment) để tự động hóa quy trình triển khai ứng dụng. Điều này giúp các nhóm phát triển phần mềm triển khai các bản cập nhật một cách nhanh chóng và hiệu quả.</p><ul><li><p><strong>Không Cần Cài Đặt Agent</strong></p></li></ul><p>Một trong những ưu điểm lớn nhất của Ansible là khả năng <strong>không yêu cầu cài đặt agent</strong> trên các máy chủ mục tiêu. Điều này giúp giảm thiểu việc sử dụng tài nguyên hệ thống và giảm thiểu độ phức tạp trong quá trình triển khai.</p><ul><li><p><strong>Ngôn Ngữ Khai Báo YAML</strong></p></li></ul><p>Ansible sử dụng <strong>YAML</strong> (Yet Another Markup Language) để viết các playbook, giúp người dùng dễ dàng tạo ra các cấu hình và tác vụ tự động mà không cần kiến thức lập trình sâu. Ngôn ngữ YAML dễ đọc và dễ hiểu, ngay cả đối với những người không phải lập trình viên.</p><ul><li><p><strong>Hỗ Trợ Nhiều Mô-đun</strong></p></li></ul><p>Ansible đi kèm với một bộ mô-đun phong phú, cho phép bạn thực hiện các tác vụ từ quản lý hệ thống, quản lý mạng, đến triển khai ứng dụng và nhiều tác vụ khác.</p><h2>Cách thức hoạt động</h2><p>Ansible hoạt động trên kiến trúc client-server, với một máy chủ điều khiển (control node) và nhiều máy khách được quản lý (managed nodes). Máy chủ điều khiển chứa kho lưu trữ trung tâm của các playbook - các tập lệnh mô tả các tác vụ cần thực hiện trên các máy khách. Sau khi triển khai, Ansible sử dụng giao thức SSH để kết nối với các máy khách và thực hiện các tác vụ được định nghĩa trong playbook theo cách thức không cần agent.</p><p>Cài đặt và cấu hình Ansible</p><p>Mình thực hành trên môi trường máy ảo, mình đã chuẩn bị sẵn 3 máy ảo gồm 1 máy làm máy chủ điều khiển (control machine) và 2 máy làm node với IP như sau:</p><ul><li><p>Control machine IP: <strong>192.168.0.136</strong></p></li><li><p>Máy Node 1 IP: <strong>192.168.0.102</strong></p></li><li><p>Máy Node 2 IP: <strong>192.168.0.167</strong></p></li></ul><p>Ta tiến hành Cài đặt và cấu hình Ansible trên máy chủ điều khiển (Controll machine)</p><p><strong>Bước 1: Cập nhật các gói hiện có trong hệ thống hiện tại:</strong></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">sudo apt update\nsudo apt upgrade\n</code></pre><p><strong>Bước 2: Cài đặt Anisible</strong></p><p>Theo mặc định, Phiên bản mới nhất của Ansible không có sẵn trong kho lưu trữ mặc định của Ubuntu. Vì vậy, bạn sẽ cần thêm Ansible PPA vào máy chủ của mình. Bạn có thể làm điều này bằng cách chạy lệnh sau:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">sudo apt install software-properties-common\nsudo apt-add-repository ppa:ansible/ansible\n</code></pre><p>Tiếp theo cập nhật lại và cài đặt Ansible bằng lệnh:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">sudo apt update -y\nsudo apt install ansible -y\n</code></pre><p>Có thể xem phiên bản Ansible vừa cài bằng lệnh:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ansible --version\n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-d7259413-ac68-445d-b0c8-2e8bf97f31c8.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 3: Xác định hệ thống máy khách mà bạn muốn quản lý trong tệp máy chủ</strong></p><p>Bạn có thể thực hiện việc này bằng cách chỉnh sửa tệp <code>/etc/ansible/hosts</code>:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">sudo /etc/ansible/hosts\n</code></pre><p>Trong ví dụ này mình sẽ đặt tên nhóm 2 máy <strong>node</strong> là <strong>webserver</strong> bởi vì mục địch của mình là muốn cài <strong>webserver</strong> trên 2 máy <strong>node</strong> này thông qua <strong>ansible và phía dưới tên nhóm là nơi khai báo những máy node,</strong> cấu trúc tổng quát để khai báo có thể theo là:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">[&lt;ten_nhom&gt;]\n&lt;ten_server_1&gt; ansible_ssh_host=&lt;node_ip_1&gt; ansible_user=&lt;username_login_node_1&gt;\n&lt;ten_server_2&gt; ansible_ssh_host=&lt;node_ip_2&gt; ansible_user=&lt;username_login_node_2&gt;\n</code></pre><p>Ví dụ như này:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-1-db4147ab-a7bf-45bf-96aa-f8f1d2e6df43.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Ngoài ra có thể thêm <code>ansible_password=&lt;passwork_login_node_1&gt;</code> để khai báo mật khẩu luôn nhưng mình sẽ thực hiện SSH Key để đảm bảo tính bảo mật.</p><p><strong>Bước 4: Tạo SSH Key</strong></p><p>Ta cần tạo SSH Key ở Controll machine để khi SSH vào các máy node không cần nhập mật khẩu cũng như không cần khai báo ansible_password ở file <strong>/etc/ansible/hosts</strong></p><p>Chạy lệnh sau để tạo key:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ssh-keygen -t rsa \n</code></pre><p>Khi chạy lệnh trên bạn sẽ được hỏi tên file và mật khẩu passphrase thì cứ nhập bình thường:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-2-4a75d2bc-fd9c-4976-9d97-bdf24c03dd7b.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Sau khi cấu tạo có thể kiểm tra lại bằng lệnh:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cd ~/.ssh &amp;&amp; ll\n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-3-e6d61b06-101d-4915-ac73-6d197c10cb6c.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Tiếp theo, sao chép public key này vào những máy Node bằng lệnh sau:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ssh-copy-id -i ~/.ssh/ansible.pub user@node_IP\n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-4-2c797ae3-aef7-431f-b54c-2781d70e6fbb.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Để cho chắc thì mình qua máy Node đó và chạy lệnh sau xem đã có nội dung khóa vừa chép chưa:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cat ~/.ssh/authorized_keys\n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-5-651bbfc3-3497-49d2-b735-a4eb1606688e.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Vào file cấu hình /etc/ansible/ansible.cfg</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">sudo nano /etc/ansible/ansible.cfg\n</code></pre><p>Và thêm đường dẫn tới Private Key:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-6-1c7ad86d-52c5-4592-88e3-5f6b51ddddf6.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 5: Kiểm tra Ansible đã cấu hình</strong></p><p>Ansible hiện đã được cài đặt và cấu hình. Đã đến lúc thử nghiệm Ansible.</p><p>Trên máy chủ, hãy thử ping hệ thống Máy khách của mình bằng lệnh sau:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ansible webserver -m ping\n</code></pre><p>Ví dụ như:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-7-dd14ca79-4a85-4e0c-96a6-3eeb38c873f8.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Thực hành ứng dụng Ansible</p><h2>Thực hành cài đặt LEMP Stack với Ansible</h2><p>Ở ví dụ này mình sẽ ứng dụng Ansible để cài đặt LEMP Stack cho 2 máy chủ Node đã đưa ra ở phần <strong>Cài Đặt và cấu hình Ansible</strong> bên trên.</p><p>Trên máy Control, ta thực hiện các bước tuần tự</p><p><strong>Bước 1: Thiết lập dự án Ansible Playbook</strong></p><p>Thư mục dự án chính sẽ được lưu trữ tất cả các thư mục, tệp và cấu hình playbook của chúng ta</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir project-lemp/\ncd project-lemp\n</code></pre><p>Bây giờ hãy tạo tệp cấu hình mới ‘hosts’ và ‘site.yml’, sau đó tạo một thư mục mới có tên là ‘roles’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">touch hosts site.yml\nmkdir -p roles/\n</code></pre><p>Trong đó:</p><ul><li><p><strong>hosts</strong> – Đó là một tệp kiểm kê chứa các mẩu thông tin về các máy chủ được quản lý bởi ansible. Nó cho phép bạn tạo một nhóm máy chủ giúp bạn dễ dàng quản lý và mở rộng quy mô tệp kiểm kê hơn. Tệp kiểm kê có thể được tạo bằng nhiều định dạng khác nhau, bao gồm định dạng INI và YAML.</p></li><li><p><strong>site.yml</strong> – Tệp sổ tay chính chứa nhóm máy chủ nào sẽ được quản lý bằng các vai trò có sẵn của chúng tôi.</p></li><li><p><strong>roles</strong> – đó là một nhóm sách hướng dẫn Ansible sẽ được sử dụng để cung cấp máy chủ. Các vai trò ansible có cấu trúc thư mục riêng, mỗi vai trò sẽ chứa các thư mục như task, handler, vars, v.v.</p></li></ul><p><strong>Bước 2 – Tạo role ansible cho cấu trúc thư mục</strong></p><p>Trong thư mục ‘project-lemp’, hãy chuyển đến thư mục ‘roles’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cd roles/\n</code></pre><p>Tạo thư mục và tệp cấu trúc roles cho các vai trò ‘common’, ‘web’ và ‘db’ bằng cách chạy lệnh ansible-galaxy bên dưới. tất nhiên là bạn có thể đặt tên khác</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ansible-galaxy init common\nansible-galaxy init web\nansible-galaxy init db\n</code></pre><p>Trong đó:</p><ul><li><p><strong>common</strong> là thư mục chưa những xử lý chung như update, add repository,...</p></li><li><p><strong>web</strong> là thư mục chứa những xử lý liên quan tới webserver như install nginx, apache, vhost,...</p></li><li><p><strong>db</strong> là thư mục chứa những xử lý liên quan tới Database như install mysql, create database,...</p></li></ul><p>Kiểm tra lại cấu trúc thư mục sau khi khởi tạo bằng lệnh:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">tree .\n</code></pre><p>Nếu chưa có có thể cài đặt bằng:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">apt install tree \n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-8-49903c1a-d7b7-42b7-9491-790fff493218.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 3 – Thiết file hosts và site.yml</strong></p><p>Ở trong thư mục <strong>/project-lemp,</strong> thực hiện chỉnh sửa file hosts băng nano như sau:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano hosts\n</code></pre><p>Lưu và đóng.</p><p>Tiếp theo, chỉnh sửa tệp cấu hình site.yml.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano site.yml\n</code></pre><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- hosts: webserver\n  become: yes\n\n  roles:\n    - common\n    - web\n    - db\n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-9-f76a9aec-ebc6-4ee0-a58b-de4807b3b95e.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 4 – Thiết lập common role</strong></p><p>Bên dưới danh sách các nhiệm vụ mà chúng ta sẽ thực hiện với các common role.</p><ul><li><p>Thay đổi kho lưu trữ</p></li><li><p>Cập nhật kho lưu trữ</p></li><li><p>Nâng cấp gói lên phiên bản mới nhất</p></li><li><p>Thiết lập múi giờ máy chủ</p></li></ul><p>Bây giờ hãy vào thư mục ‘common’ và chỉnh sửa cấu hình ‘task/main.yml’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cd common/\nnano tasks/main.yml\n</code></pre><p>Tạo một tác vụ để thay đổi kho lưu trữ , mình sử dụng mô-đun ‘<strong>copy</strong>’ để sao chép ‘<strong>sources.list</strong>’ ở thư mục ‘<strong>file</strong>’ sang máy chủ từ xa và lưu vào ‘<strong>/etc/apt/</strong>’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Change repository Ubuntu 22.04Step 4 - Setup 'web' Roles\n  copy:\n    src: sources.list\n    dest: /etc/apt/\n    backup: yes\n</code></pre><p>Tạo tác vụ cập nhật kho lưu trữ và nâng cấp tất cả các gói lên phiên bản mới nhất bằng mô-đun ‘<strong>apt</strong>’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Update repository and Upgrade packages\n  apt:\n    upgrade: dist\n    update_cache: yes\n</code></pre><p>Bây giờ hãy tạo tác vụ định cấu hình múi giờ hệ thống bằng mô-đun <strong>timezone</strong> ansible.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Setup timezone to Asia/Jakarta\n  timezone:\n    name: Asia/Jakarta\n    state: latest\n</code></pre><p>Lưu và đóng.</p><p>Sau đó, tạo cấu hình kho lưu trữ mới ‘sources.list’ bên trong thư mục ‘files’</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano files/sources.list\n</code></pre><p>Chọn kho lưu trữ gần nhất với vị trí máy chủ của bạn, bên dưới là của mình.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">deb http://archive.ubuntu.com/ubuntu jammy main restricted universe multiverse\ndeb http://archive.ubuntu.com/ubuntu jammy-updates main restricted universe multiverse\ndeb http://archive.ubuntu.com/ubuntu jammy-security main restricted universe multiverse\ndeb http://archive.ubuntu.com/ubuntu jammy-backports main restricted universe multiverse\n</code></pre><p>Lưu và đóng.</p><p>Chúng ta đã cấu hình xong common role</p><p><strong>Bước 5: Thiết lập web role</strong></p><p>Dưới đây là chi tiết các nhiệm vụ mà chúng ta sẽ thực hiện với vai trò ‘web’:</p><ul><li><p>Cài đặt Nginx</p></li><li><p>Cài đặt PHP-FPM</p></li><li><p>Định cấu hình php.ini</p></li><li><p>Tạo một máy chủ ảo</p></li><li><p>Thêm tập tin phpinfo</p></li></ul><p>Vào thư mục ‘web’ và chỉnh sửa tệp ‘task/main.yml’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cd web/\nnano tasks/main.yml\n</code></pre><p>Tạo tác vụ đầu tiên để cài đặt nginx bằng mô-đun apt.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Install Nginx\n  apt:\n    name: nginx\n    state: latest\n</code></pre><p>Bây giờ hãy tạo tác vụ cài đặt PHP-FPM với một số phần mở rộng cơ bản. Và để cài đặt nhiều gói, chúng ta có thể sử dụng định dạng ‘danh sách’ python như bên dưới.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Instal PHP-FPM\n  apt:\n    name: ['php','php-fpm','php-common','php-cli','php-curl']\n    state: latest\n</code></pre><p>Tiếp theo, chúng tôi sẽ thêm dòng mới vào cấu hình php.ini bằng mô-đun ‘blockinfile’. Và ở cuối dòng, chúng tôi sẽ thông báo cho ansible khởi động lại dịch vụ php-fpm sau khi định cấu hình tệp php.ini.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Configure php.ini\n  blockinfile:\n    dest: /etc/php/{{ php_version }}/fpm/php.ini\n    block: |\n      date.time = Asia/Jakarta\n      cgi-fix_pathinfo = 0\n    backup: yes\n  notify: restart php-fpm\n</code></pre><p>Bây giờ chúng ta sẽ sao chép cấu hình máy chủ ảo nginx bằng mô-đun ‘template’. Mô-đun mẫu sẽ sao chép cấu hình từ thư mục ‘templates’ sang máy chủ từ xa. Chúng tôi sẽ sao chép mẫu máy chủ ảo jinja2 ‘vhost.j2’ vào thư mục ‘/etc/nginx/sites-available/’ và cuối cùng chúng tôi sẽ thông báo cho ansible khởi động lại dịch vụ nginx.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Create Nginx virtual host\n  template:\n    src: vhost.j2\n    dest: /etc/nginx/sites-available/vhost-{{ domain_name }}\n  notify: restart nginx\n</code></pre><p>Xóa vhost file nếu đã tồn tại trong /etc/nginx/sites-enabled</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Remove old vhost file if exists\n  file:\n    path: /etc/nginx/sites-enabled/vhost-{{ domain_name }}\n    state: absent\n</code></pre><p>Tạo liên kết giữa vhost vừa tạo tới /etc/nginx/sites-enabled</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Enable virtual host\n  file:\n    src: /etc/nginx/sites-available/vhost-{{ domain_name }}\n    dest: /etc/nginx/sites-enabled/vhost-{{ domain_name }}\n    state: link\n</code></pre><p>Tắt site default trong /etc/nginx/sites-enabled đi và khởi động lại</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Disable default site\n  file:\n    path: /etc/nginx/sites-enabled/default\n    state: absent\n  notify: restart nginx\n</code></pre><p>Sau đó, chúng ta sẽ tạo các tác vụ mới để tạo thư mục web-root bằng mô-đun ‘file’ và sao chép mẫu index.php vào đó.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Create web-root directory\n  file:\n    path: /var/www/{{ domain_name }}\n    state: directory\n\n- name: Upload index.html and info.php files\n  template:\n    src: index.php.j2\n    dest: /var/www/{{ domain_name }}/index.php\n</code></pre><p>Lưu và đóng.</p><p>Bây giờ chúng ta sẽ định cấu hình trình xử lý để khởi động lại dịch vụ nginx và php-fpm. Chỉnh sửa cấu hình ‘handlers/main.yml’ bằng nano.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano handlers/main.yml\n</code></pre><p>Dán cấu hình bên dưới.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: restart nginx\n  service:\n    name: nginx\n    state: restarted\n    enabled: yes\n\n- name: restart php-fpm\n  service:\n    name: php{{ php_version }}-fpm\n    state: restarted\n    enabled: yes\n</code></pre><p>Lưu và đóng.</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-10-fbc052fb-bc56-47d7-8914-ec5408b42ca0.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Tiếp theo, chúng ta sẽ chỉnh sửa cấu hình ‘vars/main.yml’. Ở trong tasks/main.yml, bạn sẽ thấy các cấu hình biến ‘{{ php_version }}’ và ‘{{ domain_name }}’. Các biến đó là những biến môi trường cho phiên bản php và tên miền sẽ được sử dụng. Biến này giúp ansible có thể tái sử dụng nhiều hơn vì chúng ta chỉ cần chỉnh sửa cấu hình biến ‘vars/main.yml’ và không cần đi chỉnh sửa từng cái riêng lẽ.</p><p>Chỉnh sửa cấu hình biến ‘vars/main.yml’ bằng trình soạn thảo nano.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano /vars/main.yml\n</code></pre><p>Dán nội dung sau, bạn có thể thay đôi cho phù hợp:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">php_version: 8.1\ndomain_name: thiendocker\n</code></pre><p>Lưu và đóng.</p><p>Bây giờ chúng ta sẽ tạo cấu hình mẫu jinja2 ‘index.php.j2’ và ‘vhost.j2’ trên thư mục ‘templates/’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano templates/index.php.j2\n</code></pre><p>Dán cấu hình bên dưới.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">&lt;html&gt;\n&lt;body&gt;\n\n&lt;h1&gt;&lt;center&gt;index.html for domain {{ domain_name }}&lt;/center&gt;&lt;/h1&gt;\n\n&lt;p&gt;\n&lt;p&gt;\n\n&lt;?php\nphpinfo();\n?&gt;\n\n&lt;/body&gt;\n&lt;/html&gt;\n</code></pre><p>Lưu và đóng.</p><p>Sau đó, tạo mẫu cho cấu hình máy chủ ảo nginx ‘vhost.j2’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano templates/vhost.j2\n</code></pre><p>Dán nội dung sau:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">server {\n    listen 80;\n    listen [::]:80;\n\n    root /var/www/{{ domain_name }};\n    index index.php index.html index.htm index.nginx-debian.html;\n\n    server_name {{ domain_name }};\n\n    location / {\n        try_files $uri $uri/ =404;\n    }\n\n    # pass PHP scripts to FastCGI server\n    #\n        location ~ \\.php$ {\n            try_files $uri =404;\n            fastcgi_split_path_info ^(.+\\.php)(/.+)$;\n            fastcgi_pass unix:/var/run/php/php{{ php_version }}-fpm.sock;\n            fastcgi_index index.php;\n            fastcgi_param SCRIPT_FILENAME $document_root$fastcgi_script_name;\n            include fastcgi_params;\n        }\n\n     #Neu ban co cai dat phpmyadmin\n     location /phpmyadmin {\n        root /usr/share/;\n        index index.php index.html index.htm;\n\n        location ~ ^/phpmyadmin/(.+\\.php)$ {\n            try_files $uri =404;\n            root /usr/share/;\n            fastcgi_pass unix:/var/run/php/php{{ php_version }}-fpm.sock;\n            fastcgi_index index.php;\n            fastcgi_param SCRIPT_FILENAME $document_root$fastcgi_script_name;\n            include fastcgi_params;\n        }\n\n        location ~* ^/phpmyadmin/(.+\\.(jpg|jpeg|gif|css|png|js|ico|html|xml|txt))$ {\n            root /usr/share/;\n        }\n    }\n}\n</code></pre><p>Lưu và đóng cấu hình và chúng ta đã hoàn tất cấu hình vai trò web.</p><p><strong>Bước 6 – Thiết lập vai trò ‘db’</strong></p><p>Dưới đây là chi tiết các nhiệm vụ sẽ thực hiện với <strong>db role</strong>.</p><ul><li><p>Cài đặt mysql</p></li><li><p>Tạo cơ sở dữ liệu MySQL</p></li><li><p>Tạo người dùng MySQL</p></li><li><p>Khởi động lại mysql</p></li></ul><p>Đi tới thư mục ‘db’ và chỉnh sửa cấu hình ‘tasks/main.yml’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cd db/\nnano tasks/main.yml\n</code></pre><p>Bây giờ hãy cài đặt các gói MySQL bằng mô-đun ‘apt’ và định dạng ‘danh sách’ python để cài đặt nhiều gói.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Install MySQL and required packages\n  apt:\n    name:\n      - mysql-server\n      - mysql-client\n      - python3-mysqldb\n      - python3-pymysql\n    state: present\n    update_cache: yes\n  notify: restart mysql\n</code></pre><p>Tiếp theo là thiết lập mật khẩu và đổi phương thức đăng nhâp cho root.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Set root password and change authentication method\n  mysql_user:\n    name: root\n    host: localhost\n    password: \"{{ mysql_root_password }}\"\n    login_unix_socket: /var/run/mysqld/mysqld.sock\n    plugin: mysql_native_password\n    state: present\n  become: true\n</code></pre><p>Sau đó thêm task để tạo cơ sở dữ liệu MySQL và người dùng, sau đó cấp tất cả các đặc quyền của người dùng cho cơ sở dữ liệu.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Create database\n  mysql_db:\n    name: '{{ db_name }}'\n    state: present\n\n- name: Create user for the database\n  mysql_user:\n    name: '{{ db_user }}'\n    password: '{{ db_pass }}'\n    encrypted: yes\n    priv: '{{ db_name }}.*:ALL'\n    state: present\n</code></pre><p>Lưu và đóng.</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-11-c4ed7f5c-3e0b-42b1-8310-8efd3b6d2db1.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Tiếp theo, chỉnh sửa cấu hình ‘handlers/main.yml’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano handlers/main.yml\n</code></pre><p>Dán cấu hình của tác vụ để khởi động lại dịch vụ MySQL.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: restart mysql\n  service:\n    name: mysql\n    state: restarted\n    enabled: yes\n</code></pre><p>Lưu và đóng.</p><p>Sau đó, chỉnh sửa cấu hình biến vars ‘vars/main.yml’.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano vars/main.yml\n</code></pre><p>Dán các biến này cho cơ sở dữ liệu MySQL và cấu hình người dùng bên dưới.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">db_name:  db_name\ndb_user: userpass\ndb_pass: dbpass\n</code></pre><p>Lưu và đóng.</p><p>Biến ‘db_pass’ có mật khẩu được mã hóa MySQL và bạn có thể tạo mật khẩu MySQL được mã hóa bằng các công cụ trực tuyến.</p><p><strong>Bước 7 – Chạy Playbook Ansible</strong></p><p>Xem thư mục dự án Ansible.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cd project-lemp/\n</code></pre><p>Chạy lệnh ansible-playbook bên dưới.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ansible-playbook -i hosts site.yml\n</code></pre><p>Bây giờ ansible sẽ chạy tất cả các vai trò mà chúng ta gán cho máy chủ. Khi hoàn tất, bạn sẽ thấy kết quả như bên dưới.</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-12-79e8d01c-9d7d-4999-a643-098960ff9df9.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-13-d797c291-5ee3-42e0-a16d-7c53c59aec1b.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 8 – Kiểm tra các dịch vụ đã cài trên máy Node</strong></p><p>Như đã làm những bước trên, chúng ta đã cài MySQL, Nginx, PHP và cấu hình vhost Nginx, ta sẽ kiểm tra lại xem đã cài đặt thành công hay chưa</p><p>Truy cập vào <code>http://your_ip</code> nếu kết quả giống bên dưới ảnh này thì đã cấu hình thành công Nginx và cài đăt xong php</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-14-0d351397-1820-452d-b1d9-559436f5628c.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Tiếp là kiểm tra đăng nhập không mật khẩu và có mật khẩu ở mysql. Nếu như đúng thì sẽ không thể đăng nhập vào mysql mà không nhập mật khẩu, chỉ cho phép đăng nhập với đầy đủ username và password</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-15-9a84326e-7261-41cd-819b-d7df60593698.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><h2>Thực hành cài đặt LAMP Stack với Ansible</h2><p><strong>Bước 1: Tạo thư mục dự án trên máy Control</strong></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir ansible_playbook &amp;&amp; cd $_\n</code></pre><p><strong>Bước 2: Tạo biến mặc định</strong></p><p>Tạo tệp biến mặc định sẽ chứa thông tin như tên miền, mật khẩu gốc MariaDB, v.v.</p><p>Trong thư mục làm việc của chúng ta, hãy tạo một thư mục con có tên vars và thêm tệp cấu hình biến.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir vars &amp;&amp; cd vars\nnano default.yml\n</code></pre><p>Trong tệp <strong>default.yml</strong>, thêm thông tin bên dưới, thay thế các biến bằng thông tin chi tiết của bạn:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">---\nmysql_root_password: \"P@ssw0rd\"\napp_user: \"apache\"\nhttp_host: \"lamp.example.com\"\nhttp_conf: \"lamp.example.com.conf\"\nhttp_port: \"80\"\ndisable_default: true\n</code></pre><p>Tạo file <strong>hosts</strong> trong <code>/ansible_playbook</code> , thêm thông tin các mấy Node và gom chúng thành 1 nhóm sau đó đặt tên như hình dưới, bạn có thể thay thế thông tin phù hợp:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">[lampstack]\nserver1 ansible_ssh_host=192.168.0.104 ansible_user=thienduong\nserver2 ansible_ssh_host=192.168.0.118 ansible_user=thienduong\n</code></pre><p><strong>Bước 3: Tạo Apache role</strong></p><p>Tạo thư mục <strong>roles</strong> từ thư mục <code>/ansible_playbook</code> và một thư mục con khác trong <strong>roles</strong> cho <strong>Apache</strong>.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir -p roles/apache\n</code></pre><p>Ở đây, chúng ta cần tạo role cho Apache và PHP, role này sẽ chứa tất cả các bước, mô-đun và mẫu cần thiết cho dịch vụ Apache.</p><p><strong>Bước 4: Tạo Apache &amp; PHP tasks</strong></p><p>Tạo tác vụ thực thi chính cho Apache và PHP, bên trong thư mục Apache</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir tasks &amp;&amp; cd tasks\nnano main.yml\n</code></pre><p>Thêm nội dung bên dưới vào tệp <strong>main.yml</strong>:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">---\n- name: Install prerequisites\n  apt: name={{ item }} update_cache=yes state=latest force_apt_get=yes\n  loop: [ 'aptitude' ]\n\n  #Apache Configuration\n- name: Install Apache and PHP Packages\n  apt: name={{ item }} update_cache=yes state=latest\n  loop: [ 'apache2', 'php', 'php-mysql', 'libapache2-mod-php' ]\n\n- name: Create document root\n  file:\n    path: \"/var/www/{{ http_host }}\"\n    state: directory\n    owner: www-data\n    mode: '0755'\n\n- name: Set up Apache virtualhost\n  template:\n    src: \"files/apache.conf.j2\"\n    dest: \"/etc/apache2/sites-available/{{ http_conf }}\"\n    \n- name: Enable new site\n  shell: /usr/sbin/a2ensite {{ http_conf }}\n  \n- name: Disable default Apache site\n  shell: /usr/sbin/a2dissite 000-default.conf\n  when: disable_default\n  notify: Reload Apache\n# UFW Configuration\n- name: \"UFW - Allow HTTP on port {{ http_port }}\"\n  ufw:\n    rule: allow\n    port: \"{{ http_port }}\"\n    proto: tcp\n\n  # PHP Info Page\n- name: Sets Up PHP Info Page\n  template:\n    src: \"files/info.php.j2\"\n    dest: \"/var/www/{{ http_host }}/info.php\"\n</code></pre><p><strong>Bước 5: Tạo Apache handler</strong></p><p>Thêm Trình xử lý cho Apache. Điều này nên được thực hiện trong thư mục roles/apache/:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir handlers &amp;&amp; cd handlers\nnano main.yml\n</code></pre><p>Thêm nội dung sau cho Apache handler</p><pre data-language=\"sql\" data-lang=\"sql\"><code class=\"language-sql\">---\n- name: Reload Apache\n  service:\n    name: apache2\n    state: reloaded\n\n- name: Restart Apache\n  service:\n    name: apache2\n    state: restarted\n</code></pre><p><strong>Bước 6: Thêm Template cho Virtualhost và trang index.php</strong></p><p>Tạo các tệp sẽ được sử dụng để tạo Virtualhost và tệp chỉ mục info.php. Điều này cũng được thực hiện trong thư mục roles/apache/:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir files &amp;&amp; cd files\n</code></pre><p>Tạo file Virtualhost</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano apache.conf.j2\n</code></pre><p>Dán nội dung dưới vào file <strong>apache.conf.j2</strong></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">&lt;VirtualHost *:{{ http_port }}&gt;\n    ServerAdmin webmaster@localhost\n    ServerName {{ http_host }}\n    ServerAlias www.{{ http_host }}\n    DocumentRoot /var/www/{{ http_host }}\n    ErrorLog ${APACHE_LOG_DIR}/error.log\n    CustomLog ${APACHE_LOG_DIR}/access.log combined\n\n    &lt;Directory /var/www/{{ http_host }}&gt;\n          Options -Indexes\n    &lt;/Directory&gt;\n\n    &lt;IfModule mod_dir.c&gt;\n        DirectoryIndex index.php index.html index.cgi index.pl  index.xhtml index.htm\n    &lt;/IfModule&gt;\n\n&lt;/VirtualHost&gt;\n</code></pre><p>Tạo file demo PHP chứa thông tin bản PHP đã cài đặt:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano info.php.j2\n</code></pre><p>Dán nội dung dưới vào file <strong>info.php.j2</strong></p><pre data-language=\"powershell\" data-lang=\"powershell\"><code class=\"language-powershell\">&lt;?php\nphpinfo();\n</code></pre><p>Sau khi thực hiện tới đây, kiểm tra lại đảm bảo cây thư mục trông như thế này:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">../apache$ tree .\n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-16-a20af717-0fdb-4ab5-a94e-071ee641e467.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 7: Tạo MariaDB role</strong></p><p>Trong thư mục <strong>roles</strong> tạo thư mục MariaDB và tạo thư mục con <strong>tasks</strong> để chứa các tác vụ liên quan đến ****MariaDB</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir -p mariadb/tasks &amp;&amp; cd mariadb/tasks\n</code></pre><p>Tạo file cấu hình cho <strong>MariaDB tasks</strong>:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nanp main.yml\n</code></pre><p>Dán nội dung dưới vào file main.yml, có thể thay đổi để phù hợp với như cầu của bạn:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">---\n- name: Install prerequisites\n  apt: name={{ item }} update_cache=yes state=latest force_apt_get=yes\n  loop: [ 'aptitude' ]\n\n #Install MariaDB server\n- name: Install MariaDB Packages\n  apt: name={{ item }} update_cache=yes state=latest\n  loop: [ 'mariadb-server', 'python3-pymysql' ]\n\n# Start MariaDB Service\n- name: Start MariaDB service\n  service:\n    name: mariadb\n    state: started\n  become: true\n\n # MariaDB Configuration\n- name: Sets the root password\n  mysql_user:\n    name: root\n    password: \"{{ mysql_root_password }}\"\n    login_unix_socket: /var/run/mysqld/mysqld.sock\n\n- name: Removes all anonymous user accounts\n  mysql_user:\n    name: ''\n    host_all: yes\n    state: absent\n    login_user: root\n    login_password: \"{{ mysql_root_password }}\"\n\n- name: Removes the MySQL test database\n  mysql_db:\n    name: test\n    state: absent\n    login_user: root\n    login_password: \"{{ mysql_root_password }}\"\n</code></pre><p>Sau khi thực hiện đến bước này thì đảm bảo rằng cấu trúc trong <strong>/ansible_playbook/roles trông như thế này:</strong></p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-17-c42cd74d-7a33-40b5-bd99-e811751e0436.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 8: Tạo Playbook cho Ansible</strong></p><p>Trong thư mục <code>/ansible_playbook</code> tạo file <strong>lampstack.yml</strong> để sử dụng các <strong>roles</strong> vừa khởi tạo ỏ những bước trên.</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano lampstack.yml\n</code></pre><p>Dán nội dụng bên dưới vào:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">---\n- name: configure lamp\n  hosts: lampstack\n  become: yes\n  become_method: sudo\n  vars_files:\n    - vars/default.yml\n  roles:\n    - apache\n    - mariadb\n</code></pre><p>Toàn bộ cây cấu hình từ thư mục làm việc sẽ trông như thế này:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-18-671fbba0-a408-46cd-8ee4-398a5316b0a6.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 9: Chạy Ansible Playbook để cài LAMP Stack</strong></p><p>Chạy lệnh sau để cài đặt LAMP Stack dựa vào Playbook đã cấu hình ở bước trên</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ansible-playbook -i hosts lampstack.yml --ask-become-pass\n</code></pre><p>Sau khi chạy lệnh trên thì bạn sẽ được hỏi mật khẩu, sau khi nhập mật khẩu sẽ tiến hành chạy các task đã cấu hình sẵn:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-19-05da62e5-d3aa-43c2-bde2-f0e42fc74810.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fbff70608-e2bb-4e4f-a36f-c39f8df742c0-799b39f7-ba8b-4f87-b255-0a71bdee37b7.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 10: Kiểm tra trên các máy node</strong></p><p>Sau khi tiến hành cài đặt các dịch vụ thông qua Ansible thì chúng ta cần kiểm tra lại trên các máy được cài đặt đã hoạt động đúng hay chưa.</p><p>Vào một trình duyệt bất kỳ, truy cập <code>http://your_node_ip/info.php</code> nêu như cài đặt đúng thì sẽ hiển thị trang thông tin PHP như sau:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-20-f79a88f0-e81a-4bb6-8f89-2f2ddc6b8fa2.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Để kiêm tra xem MySQL/MariaDB đã cài đặt đúng chưa thì hãy thử đang nhập với 2 lệnh</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">sudo mysql\n</code></pre><p>và</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">sudo mysql -u root -p\n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-21-4aeef22d-62e6-44b6-be29-59268eb277f5.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><h2>Thực hành cài đặt WordPress với Ansible</h2><p><strong>Bước 1: Tạo thư mục dự án trên máy control</strong></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir wordpress_playbook\ncd wordpress_playbook\n</code></pre><p><strong>Bước 2: Tạo file host</strong></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano hosts\n</code></pre><p>và khai báo server cũng như tên nhóm, sau đây là ví dụ (có thể tùy chỉnh phù hợp):</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">[webserver]\nserver1 ansible_host=192.168.0.118\n\n[all:vars]\nansible_user=thienduong\nansible_ssh_private_key_file=/root/.ssh/ansible_no_passphrase\n</code></pre><p><strong>Bước 3: Tạo file playbook.yml</strong></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">nano playbook.yml\n</code></pre><p>Trong file này ta sẽ khai báo tên, host, file biến và roles của Play, sau đây là ví dụ (có thể tùy chỉnh cho phù hợp)</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">- name: Install WordPress For Web Server\n  hosts: webserver\n  become: true\n  vars_files:\n    - vars/default.yml\n  roles:\n    - setup_lamp\n    - setup_wordpress\n</code></pre><p><strong>Bước 4: Tạo file /vars/default.yml chứa các biến có thể sử dụng lại</strong></p><p>Để tạo file default.yml chạy những lệnh sau</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir vars\nnano /vars/default.yml\n</code></pre><p>Sau đó dán những thông tin sau vào file (có thể chỉnh sửa cho phù hợp)</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\"> ---\n#System Settings\nphp_modules: [ 'php-curl', 'php-gd', 'php-mbstring', 'php-xml', 'php-xmlrpc', 'php-soap', 'php-intl', 'php-zip' ]\n\n#MySQL Settings\nmysql_root_password: \"p@ssWordd\"\nmysql_db: \"wordpress\"\nmysql_user: \"userwp\"\nmysql_password: \"pwWPress\"\n\n#HTTP Settings\nhttp_host: \"wordpress.thienduong.name.vn\"\nhttp_conf: \"wordpress.thienduong.name.vn.conf\"\nhttp_port: \"80\"\nbackend_servers:\n  - name: server1\n    address: 192.168.0.118\n    port: 80\nload_balancing_method: round-robin\nnginx_host: \"wordpress.thienduong.name.vn\"\nload_balancer_port: 80\n</code></pre><p><strong>Bước 5: Tạo roles setup cài đặt LAMP</strong></p><p>Đứng trong thu mục <code>/wordpress_playbook</code> , tạo thư mục roles và tạo thư mục <code>/roles/setup_lamp</code></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir roles\nmkdir /roles/setup_lamp\ncd /roles/setup_lamp\n</code></pre><p>Sau đó tạo thư mục <code>tasks</code> và <code>handlers</code> trong <code>/roles/setup_lamp</code> , sau đó tạo file <code>/tasks/main.yml</code> và dán nội dung sau (có thể thay đổi để phù hợp)</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">---\n# tasks file for setup_lamp\n- name: Install prerequisites\n  apt: name=aptitude update_cache=yes state=latest force_apt_get=yes\n  tags: [ system ]\n\n- name: Install LAMP Packages\n  apt: name={{ item }} update_cache=yes state=latest\n  loop: [ 'apache2', 'mysql-server', 'python3-pymysql', 'php', 'php-mysql', 'libapache2-mod-php' ]\n  tags: [ system ]\n\n- name: Ensure MySQL is started\n  service:\n    name: mysql\n    state: started\n    enabled: yes\n  tags: [ mysql ]\n\n- name: Install PHP Extensions\n  apt: name={{ item }} update_cache=yes state=latest\n  loop: \"{{ php_modules }}\"\n  tags: [ system ]\n\n- name: Set the root password\n  mysql_user:\n    name: root\n    password: \"{{ mysql_root_password }}\"\n    login_unix_socket: /var/run/mysqld/mysqld.sock\n  tags: [ mysql, mysql-root ]\n\n- name: Remove all anonymous user accounts\n  mysql_user:\n    name: ''\n    host_all: yes\n    state: absent\n    login_user: root\n    login_password: \"{{ mysql_root_password }}\"\n  tags: [ mysql ]\n\n- name: Remove the MySQL test database\n  mysql_db:\n    name: test\n    state: absent\n    login_user: root\n    login_password: \"{{ mysql_root_password }}\"\n  tags: [ mysql ]\n</code></pre><p><strong>Bước 6: Tạo roles setup cài đặt WordPress</strong></p><p>Trong thư mục <code>roles</code> tạo thư mục <code>/roles/setup_wordpress</code></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cd roles &amp;&amp; mkdir setup_wordpress\ncd setup_wordpress\n</code></pre><p>Sau đó tạo thư mục <code>tasks</code>, <code>handlers</code> và <code>templates</code> trong <code>/roles/setup_wordpress</code></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">mkdir tasks handlers templates\n</code></pre><p>Tạo file /tasks/main.yml và dán lần lượt nội dung của các tasks vào.</p><p>Đây là cấu hình Apache:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">---\n# tasks file for setup_wordpress\n# Apache Config vhost\n- name: Create document root\n  file:\n   path: \"/var/www/{{ http_host }}\"\n   state: directory\n   owner: \"www-data\"\n   group: \"www-data\"\n   mode: '0755'\n  tags: [ apache ]\n\n- name: Set up Apache VirtualHost\n  template:\n   src: \"apache.conf.j2\"\n   dest: \"/etc/apache2/sites-available/{{ http_conf }}\"\n  notify: Reload Apache\n  tags: [ apache ]\n\n- name: Enable rewrite module\n  shell: /usr/sbin/a2enmod rewrite\n  notify: Reload Apache\n  tags: [ apache ]\n\n- name: Enable new site\n  shell: /usr/sbin/a2ensite {{ http_conf }}\n  notify: Reload Apache\n  tags: [ apache ]\n\n- name: Disable default Apache site\n  shell: /usr/sbin/a2dissite 000-default.conf\n  notify: Restart Apache\n  tags: [ apache ]\n</code></pre><p>Đây là cấu hình Setup Database for WordPress:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\"># Setup Database for WordPress\n- name: Creates database for WordPress\n  mysql_db:\n   name: \"{{mysql_user}}\"\n   state: present\n   login_user: root\n   login_password: \"{{ mysql_root_password }}\"\n  tags: [ mysql ]\n\n- name: Create MySQL user for WordPress\n  mysql_user:\n   name: \"{{ mysql_user }}\"\n   password: \"{{ mysql_password }}\"\n   priv: \"{{ mysql_user }}.*:ALL\"\n   state: present\n   login_user: root\n   login_password: \"{{ mysql_root_password }}\"\n  tags: [ mysql ]\n</code></pre><p>Đây là cấu hình WordPress:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\"># WordPress Configuration\n- name: Download and unpack latest WordPress\n  unarchive:\n   src: https://wordpress.org/latest.tar.gz\n   dest: \"/var/www/{{ http_host }}\"\n   remote_src: yes\n   creates: \"/var/www/{{ http_host }}/wordpress\"\n  tags: [ wordpress ]\n- name: Set ownership\n  file:\n   path: \"/var/www/{{ http_host }}\"\n   state: directory\n   recurse: yes\n   owner: www-data\n   group: www-data\n  tags: [ wordpress ]\n- name: Set permissions for directories\n  shell: \"/usr/bin/find /var/www/{{ http_host }}/wordpress/ -type d -exec chmod 750 {} \\\\;\"\n  tags: [ wordpress ]\n- name: Set permissions for files\n  shell: \"/usr/bin/find /var/www/{{ http_host }}/wordpress/ -type f -exec chmod 640 {} \\\\;\"\n  tags: [ wordpress ]\n- name: Set up wp-config\n  template:\n   src: \"wp-config.php.j2\"\n   dest: \"/var/www/{{ http_host }}/wordpress/wp-config.php\"\n  tags: [ wordpress ]\n</code></pre><p>Tới đây ta đã cấu hình xong <code>tasks</code> cho <code>/roles/setup_wordpress</code> . Tiếp tực tới phần <code>handlers</code></p><p>Tạo file <code>/handlers/main.yml</code> và dán nội dung sau vào (có thể tùy chỉnh cho phù hợp):</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">---\n# handlers file for setup_wordpress\n\n- name: Reload Apache\n  ansible.builtin.service:\n    name: apache2\n    state: reloaded\n\n- name: Restart Apache\n  ansible.builtin.service:\n    name: apache2\n    state: restarted\n</code></pre><p>Tiếp đến ta tạo 2 file <code>wp-config.php.j2</code> và <code>apache.conf.j2</code> trong thư mục <code>/setup_wordpress/templates</code> với nội dung như sau (có thể thay đổi để phù hợp)</p><p>Đây là mẫu file <code>wp-config.php.j2</code>:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">&lt;?php\n/**\n * The base configuration for WordPress\n *\n * The wp-config.php creation script uses this file during the\n * installation. You don't have to use the web site, you can\n * copy this file to \"wp-config.php\" and fill in the values.\n *\n * This file contains the following configurations:\n *\n * * MySQL settings\n * * Secret keys\n * * Database table prefix\n * * ABSPATH\n *\n * @link https://codex.wordpress.org/Editing_wp-config.php\n *\n * @package WordPress\n */\n\n// ** MySQL settings - You can get this info from your web host ** //\n/** The name of the database for WordPress */\ndefine( 'DB_NAME', '{{mysql_user}}' );\n\n/** MySQL database username */\ndefine( 'DB_USER', '{{ mysql_user }}' );\n\n/** MySQL database password */\ndefine( 'DB_PASSWORD', '{{ mysql_password }}' );\n\n/** MySQL hostname */\ndefine( 'DB_HOST', 'localhost' );\n\n/** Database Charset to use in creating database tables. */\ndefine( 'DB_CHARSET', 'utf8' );\n\n/** The Database Collate type. Don't change this if in doubt. */\ndefine( 'DB_COLLATE', '' );\n\n/** Filesystem access **/\ndefine('FS_METHOD', 'direct');\n\n/**#@+\n * Authentication Unique Keys and Salts.\n *\n * Change these to different unique phrases!\n * You can generate these using the {@link https://api.wordpress.org/secret-key/1.1/salt/ WordPress.org secret-key service}\n * You can change these at any point in time to invalidate all existing cookies. This will force all users to have to log in again.\n *\n * @since 2.6.0\n */\ndefine( 'AUTH_KEY',         '{{ lookup('password', '/dev/null chars=ascii_letters length=64') }}' );\ndefine( 'SECURE_AUTH_KEY',  '{{ lookup('password', '/dev/null chars=ascii_letters length=64') }}' );\ndefine( 'LOGGED_IN_KEY',    '{{ lookup('password', '/dev/null chars=ascii_letters length=64') }}' );\ndefine( 'NONCE_KEY',        '{{ lookup('password', '/dev/null chars=ascii_letters length=64') }}' );\ndefine( 'AUTH_SALT',        '{{ lookup('password', '/dev/null chars=ascii_letters length=64') }}' );\ndefine( 'SECURE_AUTH_SALT', '{{ lookup('password', '/dev/null chars=ascii_letters length=64') }}' );\ndefine( 'LOGGED_IN_SALT',   '{{ lookup('password', '/dev/null chars=ascii_letters length=64') }}' );\ndefine( 'NONCE_SALT',       '{{ lookup('password', '/dev/null chars=ascii_letters length=64') }}' );\n\n/**#@-*/\n\n/**\n * WordPress Database Table prefix.\n *\n * You can have multiple installations in one database if you give each\n * a unique prefix. Only numbers, letters, and underscores please!\n */\n$table_prefix = 'wp_';\n\n/**\n * For developers: WordPress debugging mode.\n *\n * Change this to true to enable the display of notices during development.\n * It is strongly recommended that plugin and theme developers use WP_DEBUG\n * in their development environments.\n *\n * For information on other constants that can be used for debugging,\n * visit the Codex.\n *\n * @link https://codex.wordpress.org/Debugging_in_WordPress\n */\ndefine( 'WP_DEBUG', false );\n\n/* That's all, stop editing! Happy publishing. */\n\n/** Absolute path to the WordPress directory. */\nif ( ! defined( 'ABSPATH' ) ) {\n        define( 'ABSPATH', dirname( __FILE__ ) . '/' );\n}\n\n/** Sets up WordPress vars and included files. */\nrequire_once( ABSPATH . 'wp-settings.php' );\n</code></pre><p>Đây là mẫu file <code>apache.conf.j2</code> :</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">&lt;VirtualHost *:{{ http_port }}&gt;\n    ServerAdmin webmaster@localhost\n    ServerName {{ http_host }}\n    ServerAlias www.{{ http_host }}\n    DocumentRoot /var/www/{{ http_host }}/wordpress\n    ErrorLog ${APACHE_LOG_DIR}/error.log\n    CustomLog ${APACHE_LOG_DIR}/access.log combined\n\n    &lt;Directory /var/www/{{ http_host }}&gt;\n          Options -Indexes\n          AllowOverride All\n    &lt;/Directory&gt;\n\n    &lt;IfModule mod_dir.c&gt;\n        DirectoryIndex index.php index.html index.cgi index.pl  index.xhtml index.htm\n    &lt;/IfModule&gt;\n\n&lt;/VirtualHost&gt;\n</code></pre><p>Lưu ý cấu hình trên chỉ ở mức tham khảo, đối với mẫu <code>apache.conf.j2</code> chỉ mới cấu hình cho <code>port 80</code> chưa có bảo mật bằng chứng chỉ SSL</p><p>Thư mục roles sau khi cấu hình xong sẽ có dạng:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-22-ae234fad-57c5-4fa2-8958-ef0f0dd8c054.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 7: Chạy playbook cài đặt</strong></p><p>Đảm bảo bạn đang đứng trong thư mục chính <code>/wordpress_playbook</code></p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">cd /wordpress_playbook\n</code></pre><p>Để chạy tất cả play đã định nghĩa trong file playbook thì dùng lệnh:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ansible-playbook -i hosts playbook.yml --limit webserver --ask-become-pass\n</code></pre><p>Để chạy 1 play duy nhất thì có thể dùng lệnh sau:</p><pre data-language=\"plaintext\" data-lang=\"plaintext\"><code class=\"language-plaintext\">ansible-playbook -i hosts playbook.yml --ask-become-pass\n</code></pre><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-23-4db5be99-bc02-495a-9e7d-1a939cae40f3.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-24-875bf135-2e15-4335-a506-5217283e1879.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p><strong>Bước 8: Kiểm tra WordPress sau cài đặt</strong></p><p>Sau khi cài dặt thành công thông qua Ansible, ta kiểm tra bằng cách mở trình duyệt bất kỳ và truy cập vào <code>http://your_domain_or_ip</code> bởi vì ta cấu hình port 80 mặc định trỏ vào thu mục WordPress nêu nếu thành công thi sẽ hiện như sau:</p><p></p><img src=\"/api/v1/media/object?key=media%2Fposts%2F2026-04-03%2Fimage-25-3c346111-f415-4e71-8994-c91feccd26ca.png\" alt=\"image.png\" data-align=\"center\" style=\"max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\"><p>Vậy là chúng ta đã Cài đặt thành công WordPress thông qua quá Ansible rồi</p>"};

async function formatContentByGeminiLocally(rawContent) {
    const apiKey = config.openrouter.apiKey;
    const fallbackModels = [
        "meta-llama/llama-3.3-70b-instruct:free"
    ];
    // simplified
    console.log("Starting model request...");
    const prompt = "Hãy định dạng..."; // dummy prompt for test script
    for (const model of fallbackModels) {
        const response = await fetch("https://openrouter.ai/api/v1/chat/completions", {
            method: "POST", headers: { "Authorization": `Bearer ${apiKey}`, "Content-Type": "application/json" },
            body: JSON.stringify({ model, messages: [{ role: "user", content: prompt + rawContent.substring(0, 100) }] })
        });
        const data = await response.json();
        console.log(model, response.status);
    }
}
formatContentByGeminiLocally(payload.content).catch(console.error);
